// API key as LOCAL variable - δεν εμφανίζεται στο debug
const API_KEY = 'a760affef9b0046a841bd96a0deec063e89e0acc8cb606fbd07954dec40f7faf';

// Get ALL Greek stations (περιλαμβάνει sensors metadata)
msg.url = 'https://api.openaq.org/v3/locations?iso=GR&limit=100';
msg.method = 'GET';
msg.headers = {
    'X-API-Key': API_KEY
};

return msg;

// Pollutants που μας ενδιαφέρουν για κατηγοριοποίηση
const POLLUTANTS = ['pm25', 'pm10', 'no2'];

// Παίρνουμε όλους τους σταθμούς από την απάντηση
const stations = msg.payload.results;

// Για κάθε σταθμό, χτίζουμε sensorMap και κρατάμε μόνο όσους έχουν σχετικούς ρύπους
const stationTasks = [];

for (const station of stations) {
    const sensorMap = {};

    // Iterate over sensors and build the mapping
    for (const sensor of station.sensors || []) {
        // sensor.name είναι κάτι σαν "pm25 µg/m³" - κρατάμε μόνο το pm25 part
        const pollutantName = sensor.name.split(' ')[0].toLowerCase();

        if (POLLUTANTS.includes(pollutantName)) {
            sensorMap[sensor.id] = pollutantName;
        }
    }

    // Αν ο σταθμός έχει τουλάχιστον έναν σχετικό αισθητήρα, τον κρατάμε
    if (Object.keys(sensorMap).length > 0) {
        stationTasks.push({
            stationId: station.id,
            stationName: station.name,
            locality: station.locality || 'unknown',
            coordinates: station.coordinates,
            sensorMap: sensorMap,
            latestUrl: `https://api.openaq.org/v3/locations/${station.id}/latest`
        });
    }
}

// Επιστρέφουμε array - το split node θα τα ξεχωρίσει σε μηνύματα
msg.payload = stationTasks;

// Counter για debugging
node.warn(`Found ${stationTasks.length} GR stations with PM/NO2 sensors`);

return msg;

// Τώρα msg.payload είναι array από κάθε σταθμό (από το join node)
const stations = msg.payload;

// Build the final structure - ένα snapshot ποιότητας αέρα Ελλάδας
const ingestion_ts = new Date().toISOString();
const ts_safe = ingestion_ts.replace(/[:.]/g, '-');

const finalData = {
    ingestion_timestamp: ingestion_ts,
    country: 'GR',
    station_count: stations.length,
    pollutants_tracked: ['pm25', 'pm10', 'no2'],
    stations: stations
};

// Στατιστικά: πόσοι σταθμοί έχουν κάθε ρύπο
const counts = {
    pm25: stations.filter(s => s.has_pm25).length,
    pm10: stations.filter(s => s.has_pm10).length,
    no2: stations.filter(s => s.has_no2).length
};

// Όνομα του αντικειμένου στο Minio
const objectName = `gr_air_quality_${ts_safe}.json`;

// Metadata για searchable indexing στο Minio
msg.metaData = {
    'x-amz-meta-country': 'GR',
    'x-amz-meta-station-count': String(stations.length),
    'x-amz-meta-pm25-stations': String(counts.pm25),
    'x-amz-meta-pm10-stations': String(counts.pm10),
    'x-amz-meta-no2-stations': String(counts.no2),
    'x-amz-meta-ingestion-timestamp': String(Date.now())
};

// Για το write file node (το ίδιο path που έχουμε statically στο Save to Minio)
msg.filename = '/data/temp.json';

// Για το Save to Minio (object name στο bucket)
msg.file = objectName;
msg.objectName = objectName;

// Content - JSON string που θα γραφτεί στο temp file
msg.payload = JSON.stringify(finalData, null, 2);

// Logging για debug
node.warn(`Bundled ${stations.length} stations: PM2.5=${counts.pm25}, PM10=${counts.pm10}, NO2=${counts.no2}`);

return msg;

// Κάθε μήνυμα τώρα περιέχει ΕΝΑΝ station task (από το split)
const task = msg.payload;

// Αποθηκεύουμε τα station info στο msg για να ταξιδέψουν με το request
msg.station = {
    id: task.stationId,
    name: task.stationName,
    locality: task.locality,
    coordinates: task.coordinates
};
msg.sensorMap = task.sensorMap;

// Setup HTTP call για /latest του συγκεκριμένου σταθμού
const API_KEY = 'a760affef9b0046a841bd96a0deec063e89e0acc8cb606fbd07954dec40f7faf';

msg.url = task.latestUrl;
msg.method = 'GET';
msg.headers = {
    'X-API-Key': API_KEY
};

return msg;

// Παίρνουμε τα /latest results και τα station info από το msg
const results = msg.payload.results || [];
const station = msg.station;
const sensorMap = msg.sensorMap;

// Build clean measurements object
const measurements = {};
for (const r of results) {
    const pollutant = sensorMap[r.sensorsId];
    if (pollutant) {
        // Έχουμε mapping για αυτό το sensor - κράτα το
        measurements[pollutant] = {
            value: r.value,
            datetime: r.datetime
        };
    }
}

// Replace payload with clean station data
msg.payload = {
    station_id: station.id,
    station_name: station.name,
    locality: station.locality,
    coordinates: station.coordinates,
    measurements: measurements,
    has_pm25: 'pm25' in measurements,
    has_pm10: 'pm10' in measurements,
    has_no2: 'no2' in measurements
};

return msg;

// EEA Air Quality Index (CAQI) breakpoints - επίσημα Ευρωπαϊκά
// Πηγή: European Environment Agency (https://airindex.eea.europa.eu/)
function classifyPM25(v) {
    if (v == null) return null;
    if (v <= 10)  return 'Good';
    if (v <= 20)  return 'Fair';
    if (v <= 25)  return 'Moderate';
    if (v <= 50)  return 'Poor';
    if (v <= 75)  return 'Very Poor';
    return 'Extremely Poor';
}

function classifyPM10(v) {
    if (v == null) return null;
    if (v <= 20)  return 'Good';
    if (v <= 40)  return 'Fair';
    if (v <= 50)  return 'Moderate';
    if (v <= 100) return 'Poor';
    if (v <= 150) return 'Very Poor';
    return 'Extremely Poor';
}

function classifyNO2(v) {
    if (v == null) return null;
    if (v <= 40)  return 'Good';
    if (v <= 90)  return 'Fair';
    if (v <= 120) return 'Moderate';
    if (v <= 230) return 'Poor';
    if (v <= 340) return 'Very Poor';
    return 'Extremely Poor';
}

const SEVERITY = {
    'Good': 0,
    'Fair': 1,
    'Moderate': 2,
    'Poor': 3,
    'Very Poor': 4,
    'Extremely Poor': 5
};

const station = msg.payload;
const m = station.measurements || {};

const classifications = {};
let worstCategory = 'Good';
let worstSeverity = 0;
let worstPollutant = null;
let worstValue = null;

function check(pollutant, classifier) {
    if (!m[pollutant]) return;
    const value = m[pollutant].value;
    const category = classifier(value);
    if (category === null) return;
    classifications[pollutant] = { value, category };
    if (SEVERITY[category] > worstSeverity) {
        worstSeverity = SEVERITY[category];
        worstCategory = category;
        worstPollutant = pollutant;
        worstValue = value;
    }
}

check('pm25', classifyPM25);
check('pm10', classifyPM10);
check('no2',  classifyNO2);

msg.payload = {
    station_id: station.station_id,
    station_name: station.station_name,
    locality: station.locality,
    coordinates: station.coordinates,
    classifications: classifications,
    overall_category: worstCategory,
    severity: worstSeverity,
    worst_pollutant: worstPollutant,
    worst_value: worstValue,
    timestamp: new Date().toISOString()
};

return msg;

const a = msg.payload;
const emoji = {
    'Moderate': '⚠️',
    'Poor': '🟠',
    'Very Poor': '🛑',
    'Extremely Poor': '💀'
};

const details = Object.entries(a.classifications)
    .map(([p, c]) => `${p.toUpperCase()}=${c.value}µg/m³ (${c.category})`)
    .join(', ');

msg.payload = `${emoji[a.overall_category] || '🚨'} [AIR QUALITY ALERT] ` +
              `${a.station_name} (${a.locality}) → ${a.overall_category.toUpperCase()}. ` +
              `Worst: ${a.worst_pollutant?.toUpperCase()}=${a.worst_value}µg/m³. ` +
              `All: ${details}`;

return msg;

try {
    const data = JSON.parse(msg.payload);

    // Αποθήκευση στο flow context
    flow.set('centroids', data.centroids);
    flow.set('centroids_meta', {
        trained_at: data.trained_at,
        num_stations: data.num_stations,
        num_snapshots: data.num_snapshots,
        k: data.k
    });

    node.status({
        fill: "green", 
        shape: "dot", 
        text: `${data.centroids.length} clusters @ ${data.num_snapshots} snapshots`
    });

    msg.payload = data;
    return msg;
} catch (e) {
    node.error("Failed to parse centroids: " + e.message, msg);
    node.status({fill: "red", shape: "ring", text: "parse error"});
    return null;
}

const centroids = flow.get('centroids');

if (!centroids || centroids.length === 0) {
    node.status({fill: "red", shape: "ring", text: "no centroids!"});
    msg.payload = "⚠️ Centroids δεν έχουν φορτωθεί. Τρέξε πρώτα το άλλο flow.";
    return msg;
}

// 4 fake stations - ένας για κάθε αναμενόμενο cluster
const testStations = [
    {name: "Τυπικός μικτός σταθμός",     pm25: 6.0,  pm10: 27.0, no2: 15.0, expected: 0},
    {name: "Σταθμός μόνο με PM2.5",      pm25: 8.0,  pm10: 0.0,  no2: 0.0,  expected: 1},
    {name: "Αστικός υψηλής κυκλοφορίας", pm25: 14.0, pm10: 40.0, no2: 70.0, expected: 2},
    {name: "Roadside υψηλό NO2",         pm25: 3.0,  pm10: 12.0, no2: 60.0, expected: 3}
];

const labels = {
    0: "🟢 Καθαρή",
    1: "🔴 Σκόνη (high PM10)",
    2: "🟡 Αστική (high NO2)",
    3: "🟠 PM10 outlier"
};

function assignCluster(pm25, pm10, no2) {
    let minDist = Infinity;
    let cluster = -1;
    let distances = {};

    for (const c of centroids) {
        const d = Math.sqrt(
            Math.pow(pm25 - c.pm25, 2) +
            Math.pow(pm10 - c.pm10, 2) +
            Math.pow(no2  - c.no2,  2)
        );
        distances[`cluster_${c.cluster_id}`] = Math.round(d * 100) / 100;
        if (d < minDist) {
            minDist = d;
            cluster = c.cluster_id;
        }
    }
    return {cluster, minDist: Math.round(minDist * 100) / 100, distances};
}

const results = testStations.map(s => {
    const r = assignCluster(s.pm25, s.pm10, s.no2);
    return {
        station: s.name,
        measurements: {pm25: s.pm25, pm10: s.pm10, no2: s.no2},
        expected_cluster: s.expected,
        assigned_cluster: r.cluster,
        label: labels[r.cluster],
        distance: r.minDist,
        all_distances: r.distances,
        match: r.cluster === s.expected ? "✅ CORRECT" : "❌ WRONG"
    };
});

const correct = results.filter(r => r.match.includes("CORRECT")).length;
node.status({
    fill: correct === 4 ? "green" : "yellow", 
    shape: "dot", 
    text: `${correct}/4 correct`
});

msg.payload = {
    summary: `${correct}/4 test cases passed`,
    results: results
};
return msg;
